# Write your MySQL query statement below
select user_id, round(avg(case when activity_type = 'free_trial' then activity_duration end),2) as trial_avg_duration, round(avg(case when activity_type = 'paid' then activity_duration end),2) as paid_avg_duration from useractivity where user_id in (select user_id from useractivity where activity_type = 'paid') group by user_id